// LoadSandboxObjects loads the sandbox's SandboxObjects into the .R struct
func (o *Sandbox) LoadSandboxObjects(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.SandboxObjects = nil

	related, err := o.SandboxObjects(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Sandbox = o
	}

	o.R.SandboxObjects = related
	return nil
}

// LoadSandboxObjects loads the sandbox's SandboxObjects into the .R struct
func (os SandboxSlice) LoadSandboxObjects(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	sandboxObjects, err := os.SandboxObjects(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.SandboxObjects = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range sandboxObjects {

			if !(o.ID == rel.SandboxID) {
				continue
			}

			rel.R.Sandbox = o

			o.R.SandboxObjects = append(o.R.SandboxObjects, rel)
		}
	}

	return nil
}

type sandboxJoins[Q dialect.Joinable] struct {
	typ                       string
	SandboxClusterInfo        modAs[Q, sandboxClusterInfoColumns]
	SandboxDeprecatedAPIGroup modAs[Q, sandboxDeprecatedAPIGroupColumns]
	SandboxObjects            modAs[Q, sandboxObjectColumns]
}

func (j sandboxJoins[Q]) aliasedAs(alias string) sandboxJoins[Q] {
	return buildSandboxJoins[Q](buildSandboxColumns(alias), j.typ)
}

func buildSandboxJoins[Q dialect.Joinable](cols sandboxColumns, typ string) sandboxJoins[Q] {
	return sandboxJoins[Q]{
		typ: typ,
		SandboxClusterInfo: modAs[Q, sandboxClusterInfoColumns]{
			c: SandboxClusterInfos.Columns,
			f: func(to sandboxClusterInfoColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, SandboxClusterInfos.Name().As(to.Alias())).On(
						to.SandboxID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		SandboxDeprecatedAPIGroup: modAs[Q, sandboxDeprecatedAPIGroupColumns]{
			c: SandboxDeprecatedAPIGroups.Columns,
			f: func(to sandboxDeprecatedAPIGroupColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, SandboxDeprecatedAPIGroups.Name().As(to.Alias())).On(
						to.SandboxID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		SandboxObjects: modAs[Q, sandboxObjectColumns]{
			c: SandboxObjects.Columns,
			f: func(to sandboxObjectColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, SandboxObjects.Name().As(to.Alias())).On(
						to.SandboxID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
